use std::fs::File;
use std::io::{self, BufReader, BufRead};

struct ConfigItem {
    name: String,
    action: String,
}

fn load_config_items(filepath: &str) -> io::Result<Vec<ConfigItem>> {
    let file = File::open(filepath)?;
    let reader = BufReader::new(file);
    let mut items = Vec::new();

    for line in reader.lines() {
        let line = line?;
        if line.trim().is_empty() { continue; }

        let parts: Vec<&str> = line.split("|").collect();
        if parts.len() == 2 {
            items.push(ConfigItem {
                name: parts[0].to_string().trim().to_string(),
                action: parts[1].to_string().trim().to_string(),
            });
        }
    }
    Ok(items)
}

fn main() -> io::Result<()> {
    let config_path = "config.txt";
    let items = load_config_items(config_path)?;

    if items.is_empty() {
        println!("No configuration items found.");
        return Ok(());
    }

    for item in items {
        println!("Processing item: {}", item.name);
        println!("  Simulating action: {}", item.action);
    }
    Ok(())
}

use std::fmt::Display;
use std::error::Error;

struct Point3D {
    x: f64,
    y: f64,
    z: f64,
}

impl Display for Point3D {
    fn fmt(&self, f: &mut std::fmt::Formatter) -> std::fmt::Result {
        write!(f, "({:.2}, {:.2}, {:.2})", self.x, self.y, self.z)
    }
}

trait BoundaryChecker {
    fn check_point(&self, point: &Point3D) -> Result<(), Box<dyn Error>>;
}

struct BoundingBox {
    min_x: f64,
    max_x: f64,
    min_y: f64,
    max_y: f64,
    min_z: f64,
    max_z: f64,
}

impl BoundaryChecker for BoundingBox {
    fn check_point(&self, point: &Point3D) -> Result<(), Box<dyn Error>> {
        if point.x < self.min_x || point.x > self.max_x ||
           point.y < self.min_y || point.y > self.max_y ||
           point.z < self.min_z || point.z > self.max_z {
            return Err(format!("Point {} is outside the defined bounding box.", point).into());
        }
        Ok(())
    }
}

struct SphereBoundary {
    center: Point3D,
    radius: f64,
}

impl BoundaryChecker for SphereBoundary {
    fn check_point(&self, point: &Point3D) -> Result<(), Box<dyn Error>> {
        let distance = ((point.x - self.center.x).powi(2) +
                          (point.y - self.center.y).powi(2) +
                          (point.z - self.center.z).powi(2)).sqrt();
        if distance > self.radius {
            return Err(format!("Point {} is too far from the center radius of {}.", point, self.radius).into());
        }
        Ok(())
    }
}

fn main() -> Result<(), Box<dyn Error>> {
    let target_point = Point3D { x: 10.0, y: 5.0, z: 2.0 };

    let bbox = BoundingBox {
        min_x: 0.0, max_x: 20.0,
        min_y: 0.0, max_y: 10.0,
        min_z: -5.0, max_z: 15.0,
    };

    let sphere = SphereBoundary {
        center: Point3D { x: 5.0, y: 5.0, z: 2.0 },
        radius: 8.0,
    };

    bbox.check_point(&target_point)?;
    println!("Success: {} is within the Bounding Box.", target_point);

    sphere.check_point(&target_point)?;
    println!("Success: {} is within the Sphere Boundary.", target_point);

    Ok(())
}

use std::io::{self, Cursor, Read};
use std::mem;

struct ByteCode {
    instructions: Vec<u8>,
}

impl ByteCode {
    fn read_from_stream(reader: &mut impl Read) -> io::Result<Self> {
        let mut buffer = Vec::new();
        reader.read_to_end(&mut buffer)?;
        Ok(ByteCode { instructions: buffer })
    }

    fn peek_next_opcode(&self) -> Option<u8> {
        if self.instructions.is_empty() {
            None
        } else {
            Some(self.instructions[0])
        }
    }

    fn consume_opcode(&mut self) -> Option<u8> {
        if self.instructions.is_empty() {
            None
        } else {
            let opcode = self.instructions[0];
            self.instructions.remove(0);
            Some(opcode)
        }
    }
}

fn main() -> io::Result<()> {
    let data = b"LOAD_CONST 10
ADD 5
RET";
    let mut cursor = Cursor::new(data);
    let mut bytecode_vm = ByteCode::read_from_stream(&mut cursor)?;

    println!("Successfully loaded {} bytes of instructions.", bytecode_vm.instructions.len());

    if let Some(opcode) = bytecode_vm.peek_next_opcode() {
        println!("First instruction opcode: {}", opcode);
    } else {
        println!("No instructions found.");
    }

    let consumed = bytecode_vm.consume_opcode();
    println!("Consumed opcode: {:?}", consumed);

    Ok(())
}

use std::any::TypeId;
use std::collections::HashMap;

#[derive(Debug)]
struct UserRecord { id: u32, name: String }

#[derive(Debug)]
struct ApiError { code: u16, message: String }

trait GatewayInput {}

impl GatewayInput for UserRecord {}

impl GatewayInput for ApiError {}

fn process_request<T: std::fmt::Debug + GatewayInput + 'static>(data: T) -> Result<String, String> {
    if TypeId::of::<UserRecord>() == TypeId::of::<T>() {
        let user = unsafe { &*(std::ptr::addr_of!(data) as *const UserRecord) };
        Ok(format!("Successfully processed user ID: {}", user.id))
    } else if TypeId::of::<ApiError>() == TypeId::of::<T>() {
        let error = unsafe { &*(std::ptr::addr_of!(data) as *const ApiError) };
        Err(format!("Caught an API error: {}", error.message))
    } else {
        Err(format!("Unknown input type received: {:?}", data))
    }
}

fn main() {
    let user_data = UserRecord { id: 101, name: "Alice".to_string() };
    let process_user = process_request(user_data);
    println!("Result for User: {:?}", process_user);

    let error_data = ApiError { code: 503, message: "Service Unavailable".to_string() };
    let process_error = process_request(error_data);
    println!("Result for Error: {:?}", process_error);
}

use std::io::{self, Read};
use std::fs::File;
use std::path::Path;

struct DataStream {
    reader: Box<dyn Read>,
}

impl DataStream {
    fn new(source: impl Read + 'static) -> Self {
        DataStream { reader: Box::new(source) }
    }

    fn read_data(&mut self, buffer: &mut [u8]) -> io::Result<usize> {
        self.reader.read(buffer)
    }
}

fn main() -> io::Result<()> {
    let path = Path::new("test_input.txt");

    if !path.exists() {
        println!("Please create a file named test_input.txt to run this example.");
        return Ok(()) 
    }

    let file = File::open(path)?;
    let mut stream = DataStream::new(file);
    let mut buffer = [0; 128];

    let bytes_read = stream.read_data(&mut buffer)?;

    println!("Successfully read {} bytes from the data source.", bytes_read);
    if bytes_read > 0 {
        print!("First byte value: {}", buffer[0]);
    }

    Ok(())
}
